+                continue;
+            }
+            let mut cursor = self.nodes[i].first_child;
+            while cursor != u32::MAX {
+                if cursor == child_index {
+                    return Some(i as u32);
+                }
+                let c = cursor as usize;
+                if c >= N {
+                    break;
+                }
+                cursor = self.nodes[c].next_sibling;
+            }
+        }
