+            let d2 = record_to_digest(&record);
+            assert_eq!(d1, d2);
+            assert_ne!(d1, [0u8; 32]);
+        }
+
+        #[test]
+        fn record_to_digest_differs_for_different_records() {
+            let mut r1 = WitnessRecord::zeroed();
+            r1.sequence = 1;
+            let mut r2 = WitnessRecord::zeroed();
+            r2.sequence = 2;
+
+            assert_ne!(record_to_digest(&r1), record_to_digest(&r2));
+        }
+    }
